// Parse CSV rows
const lines = csvText.trim().split('\n');
const headers = lines[0].split(',').map(h => h.trim().replace(/^"|"$/g, ''));
const rows = [];

for (let i = 1; i < lines.length; i++) {
  if (!lines[i].trim()) continue;
  const values = lines[i].split(',').map(v => v.trim().replace(/^"|"$/g, ''));
  const row = {};
  headers.forEach((h, idx) => { row[h] = values[idx] || ''; });
  rows.push(row);
}

// Anomaly detection
const now = new Date();
const flagged = [];
const stats = { total: rows.length, delayed: 0, variance: 0, medical: 0 };
const MEDICAL_KEYWORDS = ['pharma','medical','rx','clinical','hospital','cold chain'];

for (const row of rows) {
  const flags = [];
  const status = (row['Status'] || '').toLowerCase();
  const eta = row['Expected_Delivery'] ? new Date(row['Expected_Delivery']) : null;

  if (eta && !['delivered','complete','closed'].includes(status)) {
    const hoursLate = (now - eta) / 3600000;
    if (hoursLate > 24) {
      flags.push(`DELAY: ${Math.round(hoursLate)}h overdue`);
      stats.delayed++;
    }
  }

  const expQty = parseFloat(row['Expected_Qty'] || 0);
  const actQty = parseFloat(row['Actual_Qty'] || 0);
  if (expQty > 0 && actQty >= 0) {
    const variance = Math.abs(expQty - actQty) / expQty;
    if (variance > 0.10) {
      flags.push(`INVENTORY VARIANCE: ${(variance*100).toFixed(1)}% (Exp:${expQty} Act:${actQty})`);
      stats.variance++;
    }
  }

  const rowStr = JSON.stringify(row).toLowerCase();
  if (MEDICAL_KEYWORDS.some(k => rowStr.includes(k)) && flags.length > 0) {
    flags.push('MEDICAL SHIPMENT — Chain-of-custody review required');
    stats.medical++;
  }

  if (flags.length > 0) {
    flagged.push({
      id: row['Shipment_ID'] || row['Order_ID'] || 'Unknown',
      carrier: row['Carrier'] || 'Unknown',
      destination: row['Destination'] || 'Unknown',
      flags
    });
  }
}

const summary = `3PL SCAN RESULTS\nTotal: ${stats.total} | Delayed: ${stats.delayed} | Variance: ${stats.variance} | Medical: ${stats.medical} | Flagged: ${flagged.length}`;

const flagDetail = flagged.map((f,i) => 
